import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { readFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import type { Insight, InsightQuerySource, InsightVizNode } from '../lib/posthog-client.js'

const __dirname = dirname(fileURLToPath(import.meta.url))
const CLIENT_SRC = readFileSync(resolve(__dirname, '../lib/posthog-client.ts'), 'utf8')

describe('insight types: InsightQuerySource', () => {
  it('InsightQuerySource is exported from posthog-client', () => {
    assert.ok(
      CLIENT_SRC.includes('export interface InsightQuerySource'),
      'InsightQuerySource interface must be exported from posthog-client.ts',
    )
  })

  it('InsightQuerySource conforming object compiles with kind and series', () => {
    const sample = {
      kind: 'TrendsQuery',
      series: [{ event: '$pageview', kind: 'EventsNode', name: '' }],
    } satisfies InsightQuerySource
    assert.strictEqual(sample.kind, 'TrendsQuery')
  })
})

describe('insight types: InsightVizNode', () => {
  it('InsightVizNode is exported from posthog-client', () => {
    assert.ok(
      CLIENT_SRC.includes('export interface InsightVizNode'),
      'InsightVizNode interface must be exported from posthog-client.ts',
    )
  })

  it('InsightVizNode conforming object compiles with kind InsightVizNode and source', () => {
    const source = {
      kind: 'TrendsQuery',
      series: [],
    } satisfies InsightQuerySource
    const node = {
      kind: 'InsightVizNode' as const,
      source,
    } satisfies InsightVizNode
    assert.strictEqual(node.kind, 'InsightVizNode')
  })
})

describe('insight types: Insight.query accepts InsightVizNode', () => {
  it('Insight.query field is no longer typed as plain Record<string, unknown>', () => {
    assert.ok(
      !CLIENT_SRC.includes('  query?: Record<string, unknown>\n'),
      'Insight.query must not be typed as plain Record<string, unknown> — it must accept InsightVizNode',
    )
  })

  it('Insight can be constructed with an InsightVizNode as the query field', () => {
    const vizNode = {
      kind: 'InsightVizNode' as const,
      source: { kind: 'TrendsQuery', series: [] } satisfies InsightQuerySource,
    } satisfies InsightVizNode
    const insight = {
      id: 42,
      name: 'ACH funnel',
      query: vizNode,
    } satisfies Insight
    assert.strictEqual(insight.id, 42)
    assert.strictEqual((insight.query as InsightVizNode).kind, 'InsightVizNode')
  })
})

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'

describe('helpers module: constants', () => {
  it('exports TSX constant as a string pointing to tsx binary', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.TSX, 'string', 'TSX must be a string')
    assert.ok(
      mod.TSX.includes('tsx'),
      `TSX must reference a tsx binary path, got: ${mod.TSX}`,
    )
  })

  it('exports RUN constant as a string ending with run.ts', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.RUN, 'string', 'RUN must be a string')
    assert.ok(
      mod.RUN.endsWith('run.ts'),
      `RUN must end with run.ts, got: ${mod.RUN}`,
    )
  })

  it('exports LIVE constant as a boolean', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.LIVE, 'boolean', `LIVE must be a boolean, got: ${typeof mod.LIVE}`)
  })
})

describe('helpers module: run()', () => {
  it('returns object with status (number), stdout (string), stderr (string)', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.strictEqual(typeof result.status, 'number', `status must be number, got: ${typeof result.status}`)
    assert.strictEqual(typeof result.stdout, 'string', `stdout must be string, got: ${typeof result.stdout}`)
    assert.strictEqual(typeof result.stderr, 'string', `stderr must be string, got: ${typeof result.stderr}`)
  })

  it('passes env override — token absent produces NOT SET in stdout', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.ok(
      result.stdout.includes('NOT SET'),
      `expected "NOT SET" in stdout when token is empty:\n${result.stdout}`,
    )
  })

  it('accepts optional timeout in third options argument', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' }, { timeout: 10000 })
    assert.strictEqual(
      typeof result.status,
      'number',
      `run() with timeout option must still return a numeric status, got: ${typeof result.status}`,
    )
  })
})

